import React, { useEffect, useState } from "react";
import "./Home.css";

const Home = ({ onGetStarted, onLoginClick }) => {

  /* Scroll Navbar Logic */
  const [showHeader, setShowHeader] = useState(true);
  const [lastScrollY, setLastScrollY] = useState(0);

  useEffect(() => {
    const handleScroll = () => {
      if (window.scrollY < lastScrollY) {
        setShowHeader(true);
      } else {
        setShowHeader(false);
      }
      setLastScrollY(window.scrollY);
    };

    window.addEventListener("scroll", handleScroll);
    return () => window.removeEventListener("scroll", handleScroll);
  }, [lastScrollY]);

  return (
    <div className="page">

      {/* Header */}
      <header className={`header ${showHeader ? "show" : "hide"}`}>
        <section className="title-section">
          <div className="logo">
            <img src={logo} alt="Logo" />
          </div>
          <div className="title">SHIFT-UP</div>
        </section>

        <section className="nav-section">
          <nav className="nav">
            <a href="#features">Features</a>
            <a href="#pricing">Pricing</a>
            <a href="#about">About</a>
          </nav>

          <div className="header-actions">
            <button className="btn btn-outline" onClick={onLoginClick}>
              Login
            </button>
            <button className="btn btn-primary" onClick={onGetStarted}>
              Get Started
            </button>
          </div>
        </section>
      </header>

      {/* Hero */}
      <section className="hero">
        <div className="hero-text">
          <h1>Elevate Your Business into the Future</h1>
          <p className="hero-subtitle">
            Accelerate, Optimize, Transform — seamless shift scheduling for modern teams.
          </p>

          <button className="btn btn-primary hero-cta" onClick={onGetStarted}>
            Get Started
          </button>
        </div>

        <div className="hero-image">
          <img src={heroImage} alt="Hero" />
        </div>
      </section>

      {/* Intro */}
      <section className="intro" id="features">
        <p>
          With ShiftUp, experience a seamless flow from scheduling to payday.
          Manage every shift and hour effortlessly with a system designed to streamline staff scheduling.
        </p>
      </section>

      {/* Features */}
      <section className="features-grid">
        {[
          ["Scheduling", "Plan shifts in minutes with intelligent scheduling that respects employee availability, roles, and staffing needs."],
          ["Reports & Analytics", "Access coverage and staffing reports instantly with cost breakdowns."],
          ["Shift Swap", "Employees submit swap requests through a guided workflow, keeping changes organized."],
          ["Manager Approvals", "Approve or reject swap requests while maintaining full control over coverage."],
          ["Smart Notifications", "Automatic alerts keep managers and staff informed about schedules and changes."],
          ["Manager Dashboard", "Monitor hours, coverage, and upcoming shifts at a glance."]
        ].map(([title, desc]) => (
          <article key={title} className="card">
            <h3>{title}</h3>
            <p>{desc}</p>
          </article>
        ))}
      </section>

      {/* Pricing */}
      <section className="pricing" id="pricing">
        <div className="billing-toggle">
          <button className="active">Monthly</button>
          <button>Yearly</button>
          <button>Link</button>
        </div>

        <div className="pricing-card">
          <div className="price">
            <span className="price-amount">$5</span>
            <span className="price-period">/mo</span>
          </div>

          <ul className="price-features">
            <li>Employee scheduling</li>
            <li>Shift swap requests</li>
            <li>Schedule change notifications</li>
            <li>Manager dashboard</li>
          </ul>

          <button className="btn btn-primary price-cta" onClick={onGetStarted}>
            Get Started
          </button>
        </div>
      </section>

      {/* About */}
      <section className="about" id="about">
        <h2>About ShiftUp</h2>

        <p>
          At ShiftUp, we believe in empowering businesses with smarter, more efficient ways to manage their workforce.
        </p>

        <p>
          Create schedules in minutes, employees view shifts in real-time, and managers communicate effectively with their team.
        </p>
      </section>

    </div>
  );
};

export default Home;
